const double At_UU11 = At0[pp]*pow(igt01, 2) + 2*At1[pp]*igt01*igt11 + 2*At2[pp]*igt01*igt12 + At3[pp]*pow(igt11, 2) + 2*At4[pp]*igt11*igt12 + At5[pp]*pow(igt12, 2);
const double At_UU12 = At0[pp]*igt01*igt02 + At1[pp]*igt01*igt12 + At1[pp]*igt02*igt11 + At2[pp]*igt01*igt22 + At2[pp]*igt02*igt12 + At3[pp]*igt11*igt12 + At4[pp]*igt11*igt22 + At4[pp]*pow(igt12, 2) + At5[pp]*igt12*igt22;
const double At_UU22 = At0[pp]*pow(igt02, 2) + 2*At1[pp]*igt02*igt12 + 2*At2[pp]*igt02*igt22 + At3[pp]*pow(igt12, 2) + 2*At4[pp]*igt12*igt22 + At5[pp]*pow(igt22, 2);

// --- S6c: covariant 2nd deriv of alpha DiDj_a[i,j] (6 unique) ---
const double DiDj_a00 = -C3_000*grad_0_alpha[pp] - C3_100*grad_1_alpha[pp] - C3_200*grad_2_alpha[pp] + grad2_0_0_alpha[pp];
const double DiDj_a01 = -C3_001*grad_0_alpha[pp] - C3_101*grad_1_alpha[pp] - C3_201*grad_2_alpha[pp] + grad2_0_1_alpha[pp];
const double DiDj_a02 = -C3_002*grad_0_alpha[pp] - C3_102*grad_1_alpha[pp] - C3_202*grad_2_alpha[pp] + grad2_0_2_alpha[pp];
const double DiDj_a11 = -C3_011*grad_0_alpha[pp] - C3_111*grad_1_alpha[pp] - C3_211*grad_2_alpha[pp] + grad2_1_1_alpha[pp];
const double DiDj_a12 = -C3_012*grad_0_alpha[pp] - C3_112*grad_1_alpha[pp] - C3_212*grad_2_alpha[pp] + grad2_1_2_alpha[pp];
const double DiDj_a22 = -C3_022*grad_0_alpha[pp] - C3_122*grad_1_alpha[pp] - C3_222*grad_2_alpha[pp] + grad2_2_2_alpha[pp];

// --- S6d: laplacian of alpha (full-metric) ---
const double laplacian_a = chi[pp]*igt00*(-C3_000*grad_0_alpha[pp] - C3_100*grad_1_alpha[pp] - C3_200*grad_2_alpha[pp] + grad2_0_0_alpha[pp]) + 2*chi[pp]*igt01*(-C3_001*grad_0_alpha[pp] - C3_101*grad_1_alpha[pp] - C3_201*grad_2_alpha[pp] + grad2_0_1_alpha[pp]) + 2*chi[pp]*igt02*(-C3_002*grad_0_alpha[pp] - C3_102*grad_1_alpha[pp] - C3_202*grad_2_alpha[pp] + grad2_0_2_alpha[pp]) + chi[pp]*igt11*(-C3_011*grad_0_alpha[pp] - C3_111*grad_1_alpha[pp] - C3_211*grad_2_alpha[pp] + grad2_1_1_alpha[pp]) + 2*chi[pp]*igt12*(-C3_012*grad_0_alpha[pp] - C3_112*grad_1_alpha[pp] - C3_212*grad_2_alpha[pp] + grad2_1_2_alpha[pp]) + chi[pp]*igt22*(-C3_022*grad_0_alpha[pp] - C3_122*grad_1_alpha[pp] - C3_222*grad_2_alpha[pp] + grad2_2_2_alpha[pp]);

