const double sqr_At = At0[pp]*(At0[pp]*pow(igt00, 2) + 2*At1[pp]*igt00*igt01 + 2*At2[pp]*igt00*igt02 + At3[pp]*pow(igt01, 2) + 2*At4[pp]*igt01*igt02 + At5[pp]*pow(igt02, 2)) + 2*At1[pp]*(At0[pp]*igt00*igt01 + At1[pp]*igt00*igt11 + At1[pp]*pow(igt01, 2) + At2[pp]*igt00*igt12 + At2[pp]*igt01*igt02 + At3[pp]*igt01*igt11 + At4[pp]*igt01*igt12 + At4[pp]*igt02*igt11 + At5[pp]*igt02*igt12) + 2*At2[pp]*(At0[pp]*igt00*igt02 + At1[pp]*igt00*igt12 + At1[pp]*igt01*igt02 + At2[pp]*igt00*igt22 + At2[pp]*pow(igt02, 2) + At3[pp]*igt01*igt12 + At4[pp]*igt01*igt22 + At4[pp]*igt02*igt12 + At5[pp]*igt02*igt22) + At3[pp]*(At0[pp]*pow(igt01, 2) + 2*At1[pp]*igt01*igt11 + 2*At2[pp]*igt01*igt12 + At3[pp]*pow(igt11, 2) + 2*At4[pp]*igt11*igt12 + At5[pp]*pow(igt12, 2)) + 2*At4[pp]*(At0[pp]*igt01*igt02 + At1[pp]*igt01*igt12 + At1[pp]*igt02*igt11 + At2[pp]*igt01*igt22 + At2[pp]*igt02*igt12 + At3[pp]*igt11*igt12 + At4[pp]*igt11*igt22 + At4[pp]*pow(igt12, 2) + At5[pp]*igt12*igt22) + At5[pp]*(At0[pp]*pow(igt02, 2) + 2*At1[pp]*igt02*igt12 + 2*At2[pp]*igt02*igt22 + At3[pp]*pow(igt12, 2) + 2*At4[pp]*igt12*igt22 + At5[pp]*pow(igt22, 2));

// --- S7: Lie derivatives along beta (no metric needed) ---
const double lie_b_a = beta0[pp]*grad_0_alpha[pp] + beta1[pp]*grad_1_alpha[pp] + beta2[pp]*grad_2_alpha[pp];
const double lie_b_chi = beta0[pp]*grad_0_chi[pp] + beta1[pp]*grad_1_chi[pp] + beta2[pp]*grad_2_chi[pp] - 2.0/3.0*chi[pp]*(grad_0_beta0[pp] + grad_1_beta1[pp] + grad_2_beta2[pp]);
