// --- S7b: Lie of conformal metric gt (weighted) ---
const double lie_b_gt00 = beta0[pp]*grad_0_gt0[pp] + beta1[pp]*grad_1_gt0[pp] + beta2[pp]*grad_2_gt0[pp] + (4.0/3.0)*grad_0_beta0[pp]*gt0[pp] + 2*grad_0_beta1[pp]*gt1[pp] + 2*grad_0_beta2[pp]*gt2[pp] - 2.0/3.0*grad_1_beta1[pp]*gt0[pp] - 2.0/3.0*grad_2_beta2[pp]*gt0[pp];
