const double lie_b_At00 = (4.0/3.0)*At0[pp]*grad_0_beta0[pp] - 2.0/3.0*At0[pp]*grad_1_beta1[pp] - 2.0/3.0*At0[pp]*grad_2_beta2[pp] + 2*At1[pp]*grad_0_beta1[pp] + 2*At2[pp]*grad_0_beta2[pp] + beta0[pp]*grad_0_At0[pp] + beta1[pp]*grad_1_At0[pp] + beta2[pp]*grad_2_At0[pp];
