const double lie_b_At12 = At1[pp]*grad_2_beta0[pp] + At2[pp]*grad_1_beta0[pp] + At3[pp]*grad_2_beta1[pp] - 2.0/3.0*At4[pp]*grad_0_beta0[pp] + (1.0/3.0)*At4[pp]*grad_1_beta1[pp] + (1.0/3.0)*At4[pp]*grad_2_beta2[pp] + At5[pp]*grad_1_beta2[pp] + beta0[pp]*grad_0_At4[pp] + beta1[pp]*grad_1_At4[pp] + beta2[pp]*grad_2_At4[pp];
