// --- S8: final RHS assembly ---
a_rhs[pp] = -2*K[pp]*alpha[pp] + lambda[0]*lie_b_a;
b_rhs0[pp] = B0[pp]*((3.0/4.0)*alpha[pp]*lambda_f[1] + (3.0/4.0)*lambda_f[0]) + lambda[1]*(beta0[pp]*grad_0_beta0[pp] + beta1[pp]*grad_1_beta0[pp] + beta2[pp]*grad_2_beta0[pp]);
