gt_rhs12[pp] = -2*At4[pp]*alpha[pp] + lie_b_gt12;
gt_rhs22[pp] = -2*At5[pp]*alpha[pp] + lie_b_gt22;
chi_rhs[pp] = (2.0/3.0)*K[pp]*alpha[pp]*chi[pp] + lie_b_chi;
At_rhs00[pp] = alpha[pp]*(-2*AikAkj00 + At0[pp]*K[pp]) + chi[pp]*(-DiDj_a00 + R00*alpha[pp] - 1.0/3.0*gt0[pp]*(igt00*(-DiDj_a00 + R00*alpha[pp]) + 2*igt01*(-DiDj_a01 + R01*alpha[pp]) + 2*igt02*(-DiDj_a02 + R02*alpha[pp]) + igt11*(-DiDj_a11 + R11*alpha[pp]) + 2*igt12*(-DiDj_a12 + R12*alpha[pp]) + igt22*(-DiDj_a22 + R22*alpha[pp]))) + lie_b_At00;
At_rhs01[pp] = alpha[pp]*(-2*AikAkj01 + At1[pp]*K[pp]) + chi[pp]*(-DiDj_a01 + R01*alpha[pp] - 1.0/3.0*gt1[pp]*(igt00*(-DiDj_a00 + R00*alpha[pp]) + 2*igt01*(-DiDj_a01 + R01*alpha[pp]) + 2*igt02*(-DiDj_a02 + R02*alpha[pp]) + igt11*(-DiDj_a11 + R11*alpha[pp]) + 2*igt12*(-DiDj_a12 + R12*alpha[pp]) + igt22*(-DiDj_a22 + R22*alpha[pp]))) + lie_b_At01;
At_rhs02[pp] = alpha[pp]*(-2*AikAkj02 + At2[pp]*K[pp]) + chi[pp]*(-DiDj_a02 + R02*alpha[pp] - 1.0/3.0*gt2[pp]*(igt00*(-DiDj_a00 + R00*alpha[pp]) + 2*igt01*(-DiDj_a01 + R01*alpha[pp]) + 2*igt02*(-DiDj_a02 + R02*alpha[pp]) + igt11*(-DiDj_a11 + R11*alpha[pp]) + 2*igt12*(-DiDj_a12 + R12*alpha[pp]) + igt22*(-DiDj_a22 + R22*alpha[pp]))) + lie_b_At02;
At_rhs11[pp] = alpha[pp]*(-2*AikAkj11 + At3[pp]*K[pp]) + chi[pp]*(-DiDj_a11 + R11*alpha[pp] - 1.0/3.0*gt3[pp]*(igt00*(-DiDj_a00 + R00*alpha[pp]) + 2*igt01*(-DiDj_a01 + R01*alpha[pp]) + 2*igt02*(-DiDj_a02 + R02*alpha[pp]) + igt11*(-DiDj_a11 + R11*alpha[pp]) + 2*igt12*(-DiDj_a12 + R12*alpha[pp]) + igt22*(-DiDj_a22 + R22*alpha[pp]))) + lie_b_At11;
At_rhs12[pp] = alpha[pp]*(-2*AikAkj12 + At4[pp]*K[pp]) + chi[pp]*(-DiDj_a12 + R12*alpha[pp] - 1.0/3.0*gt4[pp]*(igt00*(-DiDj_a00 + R00*alpha[pp]) + 2*igt01*(-DiDj_a01 + R01*alpha[pp]) + 2*igt02*(-DiDj_a02 + R02*alpha[pp]) + igt11*(-DiDj_a11 + R11*alpha[pp]) + 2*igt12*(-DiDj_a12 + R12*alpha[pp]) + igt22*(-DiDj_a22 + R22*alpha[pp]))) + lie_b_At12;
At_rhs22[pp] = alpha[pp]*(-2*AikAkj22 + At5[pp]*K[pp]) + chi[pp]*(-DiDj_a22 + R22*alpha[pp] - 1.0/3.0*gt5[pp]*(igt00*(-DiDj_a00 + R00*alpha[pp]) + 2*igt01*(-DiDj_a01 + R01*alpha[pp]) + 2*igt02*(-DiDj_a02 + R02*alpha[pp]) + igt11*(-DiDj_a11 + R11*alpha[pp]) + 2*igt12*(-DiDj_a12 + R12*alpha[pp]) + igt22*(-DiDj_a22 + R22*alpha[pp]))) + lie_b_At22;
K_rhs[pp] = alpha[pp]*((1.0/3.0)*pow(K[pp], 2) + sqr_At) - laplacian_a + lie_b_K;
Gt_rhs0[pp] = 2*At_UU00*C2_000*alpha[pp] - 2*At_UU00*grad_0_alpha[pp] + 4*At_UU01*C2_001*alpha[pp] - 2*At_UU01*grad_1_alpha[pp] + 4*At_UU02*C2_002*alpha[pp] - 2*At_UU02*grad_2_alpha[pp] + 2*At_UU11*C2_011*alpha[pp] + 4*At_UU12*C2_012*alpha[pp] + 2*At_UU22*C2_022*alpha[pp] - CalGt0*grad_0_beta0[pp] + (2.0/3.0)*CalGt0*(grad_0_beta0[pp] + grad_1_beta1[pp] + grad_2_beta2[pp]) - CalGt1*grad_1_beta0[pp] - CalGt2*grad_2_beta0[pp] - alpha[pp]*(3*At_UU00*grad_0_chi[pp]/chi[pp] + (4.0/3.0)*grad_0_K[pp]*igt00) - alpha[pp]*(3*At_UU01*grad_1_chi[pp]/chi[pp] + (4.0/3.0)*grad_1_K[pp]*igt01) - alpha[pp]*(3*At_UU02*grad_2_chi[pp]/chi[pp] + (4.0/3.0)*grad_2_K[pp]*igt02) + beta0[pp]*grad_0_Gt0[pp] + beta1[pp]*grad_1_Gt0[pp] + beta2[pp]*grad_2_Gt0[pp] + (4.0/3.0)*grad2_0_0_beta0[pp]*igt00 + (7.0/3.0)*grad2_0_1_beta0[pp]*igt01 + (1.0/3.0)*grad2_0_1_beta1[pp]*igt00 + (7.0/3.0)*grad2_0_2_beta0[pp]*igt02 + (1.0/3.0)*grad2_0_2_beta2[pp]*igt00 + grad2_1_1_beta0[pp]*igt11 + (1.0/3.0)*grad2_1_1_beta1[pp]*igt01 + 2*grad2_1_2_beta0[pp]*igt12 + (1.0/3.0)*grad2_1_2_beta1[pp]*igt02 + (1.0/3.0)*grad2_1_2_beta2[pp]*igt01 + grad2_2_2_beta0[pp]*igt22 + (1.0/3.0)*grad2_2_2_beta2[pp]*igt02;
